commands.cmd:
raw=$(cat /var/lib/logrotate/status) || { echo "logrotate status unreadable" >&2; exit 1; }
# Emit `sortkey<TAB>YYYY-M-D` per rotation line; newest = lexical max of key.
newest=$(printf '%s\n' "$raw" | awk '
  /^"/ {
    n=split($2, p, "-")
    if (n < 3) next
    printf "%04d%02d%02d\t%d-%d-%d\n", p[1], p[2], p[3], p[1], p[2], p[3]
  }' | sort -r | head -n1 | cut -f2) || { echo "awk/sort failed" >&2; exit 1; }
[ -n "$newest" ] || { echo "no rotation timestamps in status file" >&2; exit 1; }
count=$(printf '%s\n' "$raw" | awk '/^"/{c++} END{print c+0}') || { echo "count awk failed" >&2; exit 1; }
last_epoch=$(date -d "$newest" +%s) || { echo "GNU date -d failed (needs GNU coreutils)" >&2; exit 1; }
now_epoch=$(date +%s) || { echo "date failed" >&2; exit 1; }
days=$(awk -v a="$now_epoch" -v b="$last_epoch" 'BEGIN{d=(a-b)/86400; if(d<0)d=0; printf "%.1f", d}')
printf '{"days_since_last":"%s","last_date":"%s","tracked_files":%d}' "$days" "$newest" "$count"
